public class Codec {

    // Encodes a tree to a single string.
    public String serialize(TreeNode root) {
        StringBuilder sb = new StringBuilder();
        serializeHelper(root, sb);
        return sb.toString();
    }

    private void serializeHelper(TreeNode root, StringBuilder sb) {
        if (root == null) return;
        sb.append(root.val).append(",");
        serializeHelper(root.left, sb);
        serializeHelper(root.right, sb);
    }

    // Decodes your encoded data to tree.
    public TreeNode deserialize(String data) {
        if (data.isEmpty()) return null;
        String[] nodes = data.split(",");
        int[] index = new int[] {0};
        return deserializeHelper(nodes, index, Integer.MIN_VALUE, Integer.MAX_VALUE);
    }

    private TreeNode deserializeHelper(String[] nodes, int[] index, int min, int max) {
        if (index[0] >= nodes.length || Integer.parseInt(nodes[index[0]]) < min || Integer.parseInt(nodes[index[0]]) > max) {
            return null;
        }
        TreeNode node = new TreeNode(Integer.parseInt(nodes[index[0]++]));
        node.left = deserializeHelper(nodes, index, min, node.val);
        node.right = deserializeHelper(nodes, index, node.val, max);
        return node;
    }
}
